import jsPDF from 'jspdf';

// ── A4 layout constants (mm) ──────────────────────────────────────────────────
const PAGE_W      = 210;
const PAGE_H      = 297;
const MARGIN_X    = 20;
const MARGIN_TOP  = 20;
const MARGIN_BOT  = 20;
const CONTENT_W   = PAGE_W - MARGIN_X * 2;

/**
 * Writes real vector text into the PDF — sharp at any zoom, fully selectable,
 * copy-pasteable and editable in Acrobat/Preview.
 *
 * @param {object} docData  - All document fields (see App.js)
 * @param {string} filename - Output filename without extension
 */
export function exportToPDF(docData, filename = 'assessment-sheet') {
  const {
    tpl, studentName, uid, section,
    worksheetNo, datePerf, sectionContent,
  } = docData;

  const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  // ── font size helpers ──────────────────────────────────────────────────────
  const BASE   = tpl.fontSize  || 12;   // pt → treated as mm-scaled below
  const H1     = BASE + 4;
  const H2     = BASE + 1;
  const SMALL  = BASE - 1;
  const LINE_H = BASE * 0.45 * (tpl.spacing || 1.6); // mm per line

  let y = MARGIN_TOP; // current Y cursor in mm

  // ── helper: check page overflow and add new page ───────────────────────────
  const checkPage = (needed = LINE_H) => {
    if (y + needed > PAGE_H - MARGIN_BOT) {
      pdf.addPage();
      y = MARGIN_TOP;
    }
  };

  // ── helper: wrapped text block, returns new Y ──────────────────────────────
  const writeText = (text, x, maxW, lineH, align = 'left') => {
    if (!text) return;
    const lines = pdf.splitTextToSize(String(text), maxW);
    lines.forEach(line => {
      checkPage(lineH);
      pdf.text(line, align === 'center' ? PAGE_W / 2 : x, y, { align });
      y += lineH;
    });
  };

  // ── helper: horizontal rule ────────────────────────────────────────────────
  const hRule = (thickness = 0.4) => {
    checkPage(3);
    pdf.setDrawColor(40, 40, 40);
    pdf.setLineWidth(thickness);
    pdf.line(MARGIN_X, y, PAGE_W - MARGIN_X, y);
    y += 3;
  };

  // ══════════════════════════════════════════════════════════════════════════
  // 1. HEADER
  // ══════════════════════════════════════════════════════════════════════════
  pdf.setFont('times', 'bold');
  pdf.setFontSize(H1 + 4);
  pdf.setTextColor(10, 10, 10);
  writeText(tpl.university || 'University Name', MARGIN_X, CONTENT_W, LINE_H * 1.3, 'center');

  pdf.setFont('times', 'italic');
  pdf.setFontSize(SMALL);
  pdf.setTextColor(80, 80, 80);
  writeText('Discover. Learn. Empower.', MARGIN_X, CONTENT_W, LINE_H, 'center');

  y += 3;
  hRule(0.8);

  pdf.setFont('times', 'bold');
  pdf.setFontSize(H1);
  pdf.setTextColor(10, 10, 10);
  writeText(`Worksheet ${worksheetNo}`, MARGIN_X, CONTENT_W, LINE_H * 1.4, 'center');

  y += 2;
  hRule(0.4);
  y += 2;

  // ══════════════════════════════════════════════════════════════════════════
  // 2. STUDENT INFO (2-column table)
  // ══════════════════════════════════════════════════════════════════════════
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(BASE);
  pdf.setTextColor(20, 20, 20);

  const infoRows = [
    [['Student Name', studentName],  ['UID', uid]],
    [['Branch', tpl.branch],         ['Section/Group', section]],
    [['Semester', tpl.semester],     ['Date of Performance', datePerf]],
    [['Subject Name', tpl.subject],  ['Subject Code', tpl.subjectCode]],
  ];
  const colW  = CONTENT_W / 2;
  const rowH  = LINE_H * 1.3;

  infoRows.forEach(row => {
    checkPage(rowH);
    row.forEach(([label, value], ci) => {
      const x = MARGIN_X + ci * colW;
      pdf.setFont('helvetica', 'bold');
      pdf.text(`${label}: `, x, y);
      const labelW = pdf.getTextWidth(`${label}: `);
      pdf.setFont('helvetica', 'normal');
      pdf.text(String(value || ''), x + labelW, y);
    });
    y += rowH;
  });

  y += 3;
  hRule(0.5);
  y += 4;

  // ══════════════════════════════════════════════════════════════════════════
  // 3. SECTIONS
  // ══════════════════════════════════════════════════════════════════════════
  tpl.sections.forEach((sec, i) => {
    // Section heading
    checkPage(LINE_H * 2);
    pdf.setFont('times', 'bold');
    pdf.setFontSize(H2);
    pdf.setTextColor(10, 10, 10);
    writeText(`${i + 1}. ${sec}:`, MARGIN_X, CONTENT_W, LINE_H * 1.4);

    // Thin underline under heading
    pdf.setDrawColor(180, 180, 180);
    pdf.setLineWidth(0.2);
    pdf.line(MARGIN_X, y, PAGE_W - MARGIN_X, y);
    y += 2;

    // Section body
    const content = sectionContent[sec] || '';
    const isCode  = sec.toLowerCase().includes('code') || sec.toLowerCase().includes('procedure/code');

    if (isCode && content) {
      // Code block: light grey background, monospace font
      pdf.setFont('courier', 'normal');
      pdf.setFontSize(BASE - 1);
      pdf.setTextColor(20, 20, 20);

      const codeLines = pdf.splitTextToSize(content, CONTENT_W - 8);
      const blockH    = codeLines.length * LINE_H * 0.95 + 6;

      checkPage(Math.min(blockH, PAGE_H - MARGIN_TOP - MARGIN_BOT));

      // Grey background rect
      pdf.setFillColor(245, 245, 245);
      pdf.setDrawColor(200, 200, 200);
      pdf.setLineWidth(0.2);
      pdf.roundedRect(MARGIN_X, y, CONTENT_W, Math.min(blockH, PAGE_H - y - MARGIN_BOT), 2, 2, 'FD');

      y += 3;
      codeLines.forEach(line => {
        checkPage(LINE_H * 0.95);
        pdf.text(line, MARGIN_X + 4, y);
        y += LINE_H * 0.95;
      });
      y += 3;
    } else {
      // Normal text
      pdf.setFont('helvetica', 'normal');
      pdf.setFontSize(BASE);
      pdf.setTextColor(30, 30, 30);
      const align = tpl.align === 'center' ? 'center' : 'left';
      writeText(content || '(no content)', MARGIN_X + 2, CONTENT_W - 4, LINE_H, align);
    }

    y += 4; // spacing between sections
  });

  // ══════════════════════════════════════════════════════════════════════════
  // 4. PAGE NUMBERS
  // ══════════════════════════════════════════════════════════════════════════
  const totalPages = pdf.getNumberOfPages();
  for (let p = 1; p <= totalPages; p++) {
    pdf.setPage(p);
    pdf.setFont('helvetica', 'normal');
    pdf.setFontSize(9);
    pdf.setTextColor(150, 150, 150);
    pdf.text(`Page ${p} of ${totalPages}`, PAGE_W / 2, PAGE_H - 8, { align: 'center' });
  }

  pdf.save(`${filename}.pdf`);
}
